for idea_dir in os.listdir(base_dir):
    parts = idea_dir.split("_")
    matched_key = None
    for k in ideas_data.keys():
        if idea_dir.startswith(k.split("_")[0] + "_" + k.split("_")[1]):
            matched_key = k
            break
            
    if matched_key:
        desc_path = os.path.join(base_dir, idea_dir, "описание.json")
        with open(desc_path, "w", encoding="utf-8") as f:
            json.dump(ideas_data[matched_key], f, ensure_ascii=False, indent=2)
        print(f"Сгенерирован контент для: {idea_dir}")

